// Note is the resolver for the note field.
func (r *queryResolver) Note(ctx context.Context, input model.NoteInput) (*model.PublicNote, error) {
	req, err := appreq.FromCtx(ctx)
	if err != nil {
		return nil, err
	}

	userToken, err := req.UserToken()
	if err != nil {
		return nil, err
	}

	request := rendernotepage.Request{
		Path:      input.Path,
		Referrer:  input.Referer,
		UserToken: userToken,
	}

	response, err := rendernotepage.Resolve(ctx, r.env(ctx), request)
	if err != nil {
		return nil, err
	}

	if response.Note == nil {
		return nil, nil
	}

	// Convert note headings to TOC items
	toc := make([]model.NoteTocItem, 0, len(response.Note.TOC()))
	for _, heading := range response.Note.TOC() {
		level := heading.Level
		if level > 2147483647 {
			level = 2147483647 // Cap at max int32 value
		}
		toc = append(toc, model.NoteTocItem{
			ID:    heading.ID,
			Title: heading.Text,
			Level: int32(level), //nolint:gosec // heading level is always a small positive number
		})
	}

	return &model.PublicNote{
		Title: response.Note.Title,
		HTML:  string(response.Note.HTML),
		Toc:   toc,
	}, nil
}

