// Role is the resolver for the role field.
func (r *viewerResolver) Role(ctx context.Context, obj *appmodel.Viewer) (model.Role, error) {
	if obj.UserToken != nil {
		role := model.Role(strings.ToUpper(obj.UserToken.Role))
		if role.IsValid() {
			return role, nil
		} else {
			r.env(ctx).Logger().Warn("invalid role in token", "role", role, "token", obj.UserToken)
		}
	}

	if obj.UserID == nil {
		return model.RoleGuest, nil
	}

	_, err := r.env(ctx).AdminByUserID(ctx, *obj.UserID)
	if err != nil {
		if db.IsNoFound(err) {
			return model.RoleUser, nil
		}

		return model.RoleGuest, err
	}

	return model.RoleAdmin, nil
}

// User is the resolver for the user field.
func (r *viewerResolver) User(ctx context.Context, obj *appmodel.Viewer) (*db.User, error) {
	// cases can just set the userID to the viewer
	userID := obj.UserID

	// if it not set, we can try to get it from the token
	if userID == nil && obj.UserToken != nil {
		v := int64(obj.UserToken.ID)
		userID = &v
	}

	if userID != nil {
		user, err := r.env(ctx).UserByID(ctx, *userID)
		if err != nil {
			if errors.Is(err, sql.ErrNoRows) {
				return nil, nil
			}

			return nil, err
		}

		return &user, nil
	}

	return nil, nil
}

// Offers is the resolver for the offers field.
func (r *viewerResolver) Offers(ctx context.Context, obj *appmodel.Viewer, filter model.ViewerOffersFilter) (model.ViewerOffers, error) {
	if filter.PageID == nil {
		return nil, nil
	}

	note := r.env(ctx).LiveNoteViews().GetByPathID(*filter.PageID)
	if note == nil {
		return nil, nil
	}

	offers, err := r.env(ctx).ListActiveOffersBySubgraphNames(ctx, note.SubgraphNames)
	if err != nil {
		return nil, err
	}

	if len(offers) > 0 {
		return &model.ActiveOffers{Nodes: offers}, nil
	}

	wl := model.SubgraphWaitList{
		EmailAllowed: true,
	}

	bots, err := r.env(ctx).ListEnabledTgBots(ctx)
	if err != nil {
		return nil, err
	}

	if len(bots) > 0 {
		botURL := fmt.Sprintf("https://t.me/%s?start=wl_%d", bots[0].Name, note.PathID)

		wl.TgBotURL = &botURL
	}

	return &wl, nil
}

// ActivePurchases is the resolver for the activePurchases field.
func (r *viewerResolver) ActivePurchases(ctx context.Context, obj *appmodel.Viewer) ([]db.Purchase, error) {
	if obj.UserID != nil {
		return r.env(ctx).ListActivePurchasesByUserID(ctx, sql.NullInt64{Valid: true, Int64: *obj.UserID})
	}

	ids, err := r.env(ctx).ExtractPurchaseTokenIDs(ctx)
	if err != nil {
		return nil, err
	}

	if len(ids) == 0 {
		return nil, nil
	}

	return r.env(ctx).ListActivePurchasesByIDs(ctx, ids)
}

